SELECT 
  FROM er.tn_oom_check_addl_rqst r
 WHERE r.oom_id  = #{oomId}
   AND r.rqst_sn = #{rqstSn}
   AND NOW() BETWEEN r.use_bgng_dt AND r.use_end_dt

SELECT COALESCE(MAX(rqst_sn), 0) + 1
  FROM er.tn_oom_check_addl_rqst
 WHERE oom_id = #{oomId}

mapper.update:
UPDATE er.tn_oom_check_addl_rqst
   SET resp_dt          = NOW(),
       resp_user_id     = #{respUserId},
       resp_cn          = #{respCn},
       last_chg_dt      = NOW(),
       last_chg_user_id = #{respUserId}
 WHERE oom_id  = #{oomId}
   AND rqst_sn = #{rqstSn}
   AND resp_dt IS NULL
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

UPDATE er.tn_oom_check_addl_rqst
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE oom_id  = #{oomId}
   AND rqst_sn = #{rqstSn}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
